/**
 * Unit tests for multi-instance-quality-gate hook
 * Tests quality gate enforcement in multi-instance merge/deploy scenarios
 */

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { mockCommonBasic } from '../../fixtures/mock-common.js';

vi.mock('../../../lib/common.js', () => mockCommonBasic());

vi.mock('../../../lib/agent-teams.js', () => ({
  isAgentTeamsActive: vi.fn(() => false),
}));

vi.mock('node:fs', () => ({
  existsSync: vi.fn(() => false),
  readFileSync: vi.fn(() => '{}'),
}));

vi.mock('node:path', () => {
  const named = {
    join: vi.fn((...args: string[]) => args.join('/')),
    basename: vi.fn((p: string) => p.split('/').pop() || ''),
    dirname: vi.fn((p: string) => p.split('/').slice(0, -1).join('/')),
    resolve: vi.fn((...a: string[]) => a.join('/')),
    sep: '/',
  };
  return { ...named, default: named };
});

import { multiInstanceQualityGate } from '../../../pretool/bash/multi-instance-quality-gate.js';
import { isAgentTeamsActive } from '../../../lib/agent-teams.js';
import type { HookInput } from '../../../types.js';
import { existsSync, readFileSync } from 'node:fs';
import { createTestContext } from '../../fixtures/test-context.js';

function makeInput(command: string): HookInput {
  return {
    tool_name: 'Bash',
    session_id: 'test-session-123',
    project_dir: '/test/project',
    tool_input: { command },
  };
}

let ctx: ReturnType<typeof createTestContext>;

describe('multi-instance-quality-gate', () => {
  beforeEach(() => {
    ctx = createTestContext();
    vi.clearAllMocks();
    vi.mocked(isAgentTeamsActive).mockReturnValue(false);
    vi.mocked(existsSync).mockReturnValue(false);
    vi.mocked(readFileSync).mockReturnValue('{}');
  });

  // --- Silent cases ---

  it('returns silent success for non-merge commands', () => {
    const result = multiInstanceQualityGate(makeInput('npm install'), ctx);

    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
    expect(result.hookSpecificOutput).toBeUndefined();
  });

  it('returns silent success when agent teams is active', () => {
    vi.mocked(isAgentTeamsActive).mockReturnValue(true);

    const result = multiInstanceQualityGate(makeInput('gh pr merge 42'), ctx);

    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
  });

  it('returns silent success when no coordination DB exists', () => {
    // existsSync returns false by default — no .claude/coordination/.claude.db
    const result = multiInstanceQualityGate(makeInput('gh pr merge 42'), ctx);

    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
  });

  it('returns silent success when all quality gates pass', () => {
    // coordination DB exists
    vi.mocked(existsSync).mockImplementation((p: unknown) => {
      const path = String(p);
      if (path.includes('.claude.db')) return true;
      if (path.includes('work-registry.json')) return true;
      return false;
    });
    // All gates pass
    vi.mocked(readFileSync).mockReturnValue(
      JSON.stringify({ qualityGates: { tests: true, lint: true, typecheck: true } }),
    );

    const result = multiInstanceQualityGate(makeInput('gh pr merge 42'), ctx);

    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
  });

  // --- Context injection cases ---

  it('returns failed gates context when tests/lint/typecheck fail', () => {
    vi.mocked(existsSync).mockImplementation((p: unknown) => {
      const path = String(p);
      if (path.includes('.claude.db')) return true;
      if (path.includes('work-registry.json')) return true;
      return false;
    });
    // No gates pass (empty object)
    vi.mocked(readFileSync).mockReturnValue(JSON.stringify({ qualityGates: {} }));

    const result = multiInstanceQualityGate(makeInput('gh pr merge 42'), ctx);

    expect(result.continue).toBe(true);
    expect(result.hookSpecificOutput?.additionalContext).toContain('tests');
    expect(result.hookSpecificOutput?.additionalContext).toContain('lint');
    expect(result.hookSpecificOutput?.additionalContext).toContain('typecheck');
    expect(result.hookSpecificOutput?.additionalContext).toContain('Failed/missing gates');
  });

  it('includes only failed gate names in context', () => {
    vi.mocked(existsSync).mockImplementation((p: unknown) => {
      const path = String(p);
      if (path.includes('.claude.db')) return true;
      if (path.includes('work-registry.json')) return true;
      return false;
    });
    // Only tests pass
    vi.mocked(readFileSync).mockReturnValue(
      JSON.stringify({ qualityGates: { tests: true, lint: false, typecheck: false } }),
    );

    const result = multiInstanceQualityGate(makeInput('git merge feature-branch'), ctx);

    expect(result.hookSpecificOutput?.additionalContext).toContain('lint');
    expect(result.hookSpecificOutput?.additionalContext).toContain('typecheck');
    expect(result.hookSpecificOutput?.additionalContext).not.toContain('Failed/missing gates: tests');
  });

  it('matches deploy commands', () => {
    vi.mocked(existsSync).mockReturnValue(true);
    vi.mocked(readFileSync).mockReturnValue(JSON.stringify({ qualityGates: {} }));

    const result = multiInstanceQualityGate(makeInput('deploy production'), ctx);

    expect(result.continue).toBe(true);
    expect(result.hookSpecificOutput?.additionalContext).toContain('Failed/missing gates');
  });

  it('logs permission and hook event on failed gates', () => {
    vi.mocked(existsSync).mockReturnValue(true);
    vi.mocked(readFileSync).mockReturnValue(JSON.stringify({ qualityGates: {} }));

    multiInstanceQualityGate(makeInput('gh pr merge 42'), ctx);

    expect(ctx.logPermission).toHaveBeenCalledWith(
      'allow',
      expect.stringContaining('Quality gates failed'),
      expect.any(Object),
    );
    expect(ctx.log).toHaveBeenCalledWith(
      'multi-instance-quality-gate',
      expect.stringContaining('Failed'),
    );
  });
});
